import { useState } from 'react';
import './App.css';
import { useLocalStorage } from './hooks/useLocalStorage';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Training from './pages/Training';
import Nutrition from './pages/Nutrition';

export default function App() {
  const [page, setPage] = useState('dashboard');
  const [sessions, setSessions] = useLocalStorage('sessions', []);
  const [nutrition, setNutrition] = useLocalStorage('nutrition', {});

  const pages = {
    dashboard: <Dashboard sessions={sessions} nutrition={nutrition} />,
    training:  <Training sessions={sessions} setSessions={setSessions} />,
    nutrition: <Nutrition nutrition={nutrition} setNutrition={setNutrition} />,
  };

  return (
    <div className="app-layout">
      <Sidebar page={page} setPage={setPage} />
      <main className="app-main">
        {pages[page]}
      </main>
    </div>
  );
}
